"use client";

import { motion, AnimatePresence } from "framer-motion";
import { X, ArrowRight, CheckCircle2 } from "lucide-react";
import Image from "next/image";

interface Project {
  number: string;
  title: string;
  category: string;
  description: string;
  tags: string[];
  image: string;
  challenge: string;
  solution: string;
  metrics: string[];
}

interface ProjectModalProps {
  project: Project | null;
  isOpen: boolean;
  onClose: () => void;
}

export default function ProjectModal({ project, isOpen, onClose }: ProjectModalProps) {
  if (!project) return null;

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-charcoal/90 backdrop-blur-sm z-[100] cursor-pointer"
          />

          {/* Modal Container */}
          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="fixed inset-4 md:inset-10 lg:inset-20 z-[101] bg-charcoal border border-vanilla/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col lg:flex-row"
          >
            {/* Close Button */}
            <button 
              onClick={onClose}
              className="absolute top-6 right-6 z-[110] p-2 bg-charcoal/50 backdrop-blur-md rounded-full border border-vanilla/10 text-vanilla hover:text-orange hover:border-orange/40 transition-all"
            >
              <X size={24} />
            </button>

            {/* Left Column - Image & Meta */}
            <div className="lg:w-1/2 relative bg-[#1a1a1a] h-[300px] lg:h-full">
              <Image 
                src={project.image} 
                alt={project.title}
                fill
                className="object-cover"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-charcoal via-transparent to-transparent lg:hidden" />
              
              <div className="absolute bottom-8 left-8 hidden lg:block">
                 <span className="font-pixel text-orange text-[12px] mb-2 block tracking-widest">{project.number}</span>
                 <h2 className="font-heading text-[48px] font-bold text-vanilla leading-none">{project.title}</h2>
                 <p className="font-body text-vanilla/60 mt-4 text-[18px]">{project.category}</p>
              </div>
            </div>

            {/* Right Column - Content */}
            <div className="lg:w-1/2 h-full overflow-y-auto bg-charcoal p-8 md:p-12 lg:p-16 custom-scrollbar">
              {/* Mobile Header */}
              <div className="lg:hidden mb-10">
                 <span className="font-pixel text-orange text-[10px] mb-2 block tracking-widest">{project.number}</span>
                 <h2 className="font-heading text-[32px] font-bold text-vanilla leading-none">{project.title}</h2>
                 <p className="font-body text-vanilla/60 mt-2 text-[16px]">{project.category}</p>
              </div>

              {/* Sections */}
              <div className="space-y-12">
                <div>
                  <h3 className="font-pixel text-orange text-[10px] uppercase tracking-widest mb-4">The Challenge</h3>
                  <p className="font-body text-vanilla/70 text-[18px] leading-[1.6]">
                    {project.challenge}
                  </p>
                </div>

                <div>
                  <h3 className="font-pixel text-orange text-[10px] uppercase tracking-widest mb-4">The Solution</h3>
                  <p className="font-body text-vanilla/70 text-[18px] leading-[1.6]">
                    {project.solution}
                  </p>
                </div>

                <div>
                  <h3 className="font-pixel text-orange text-[10px] uppercase tracking-widest mb-6">Key Metrics</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {project.metrics.map((metric, i) => (
                      <div key={i} className="flex items-center gap-3 bg-vanilla/[0.03] border border-vanilla/5 p-4 rounded-xl">
                        <CheckCircle2 size={18} className="text-orange shrink-0" />
                        <span className="font-body text-vanilla/80 text-[14px]">{metric}</span>
                      </div>
                    ))}
                  </div>
                </div>

                <div>
                  <h3 className="font-pixel text-orange text-[10px] uppercase tracking-widest mb-4">Tags</h3>
                  <div className="flex flex-wrap gap-2">
                    {project.tags.map((tag) => (
                      <span key={tag} className="font-body text-[12px] text-vanilla/40 border border-vanilla/10 px-3 py-1.5 rounded-full">
                        {tag}
                      </span>
                    ))}
                  </div>
                </div>

                <div className="pt-8">
                  <motion.button
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    className="w-full bg-orange text-white py-5 rounded-2xl font-heading font-bold text-[16px] flex items-center justify-center gap-2 group transition-shadow hover:shadow-[0_0_20px_rgba(254,81,2,0.3)]"
                  >
                    View Project Live
                    <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
                  </motion.button>
                </div>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
}
