"use client";

import { useState } from "react";
import { ArrowUpRight, Send, Terminal as TerminalIcon } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import Magnet from "@/components/ui/Magnet";

const contactLinks = [
  { label: "Email", value: "atharavnarang05@gmail.com", href: "mailto:atharavnarang05@gmail.com" },
  { label: "LinkedIn", value: "linkedin.com/in/atharav-narang-132b74273", href: "https://www.linkedin.com/in/atharav-narang-132b74273/" },
  { label: "GitHub", value: "github.com/Atharav001", href: "https://github.com/Atharav001" },
];

const itemVariants = {
  hidden: { opacity: 0, y: 40 },
  visible: {
    opacity: 1,
    y: 0,
    transition: {
      duration: 0.8,
      ease: "easeOut",
    },
  },
};

export default function Contact() {
  const [formState, setFormState] = useState({ name: "", email: "", message: "" });
  const [isSubmitted, setIsSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitted(true);
    setTimeout(() => setIsSubmitted(false), 3000);
  };

  return (
    <section id="contact" className="relative py-32 px-8 md:px-16 lg:px-24">
      <div className="max-w-[1400px] mx-auto">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-20">
          {/* Left Column - Info */}
          <div>
            <motion.h2
              initial="hidden"
              whileInView="visible"
              viewport={{ once: true, amount: 0.2 }}
              variants={itemVariants}
              className="font-pixel text-orange text-[clamp(2rem,6vw,5rem)] leading-[0.95] mb-6"
            >
              {"Let's"}
              <br />
              Connect
            </motion.h2>
            <motion.p
              initial="hidden"
              whileInView="visible"
              viewport={{ once: true, amount: 0.2 }}
              variants={itemVariants}
              transition={{ duration: 0.8, delay: 0.1 }}
              className="font-body text-vanilla/60 text-[clamp(1rem,1.5vw,1.25rem)] leading-[1.6] max-w-[500px] mb-12"
            >
              Interested in working together? Use the terminal to send a secure transmission or reach out through traditional channels.
            </motion.p>

            <div className="flex flex-col gap-4">
              {contactLinks.map((link, i) => (
                <motion.a
                  key={link.label}
                  href={link.href}
                  initial={{ opacity: 0, x: -20 }}
                  whileInView={{ opacity: 1, x: 0 }}
                  viewport={{ once: true }}
                  transition={{ delay: 0.2 + i * 0.1 }}
                  className="group flex items-center justify-between bg-vanilla/[0.03] border border-vanilla/5 p-6 rounded-2xl hover:border-orange/30 transition-all max-w-[400px]"
                >
                  <div>
                    <p className="font-body text-[12px] text-muted mb-1">{link.label}</p>
                    <p className="font-body text-[16px] text-vanilla group-hover:text-orange transition-colors">{link.value}</p>
                  </div>
                  <ArrowUpRight size={18} className="text-muted group-hover:text-orange transition-all group-hover:rotate-45" />
                </motion.a>
              ))}
            </div>
          </div>

          {/* Right Column - Terminal Form */}
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            className="relative bg-charcoal border border-vanilla/10 rounded-3xl overflow-hidden shadow-2xl"
          >
            {/* Terminal Header */}
            <div className="bg-vanilla/5 px-6 py-4 flex items-center justify-between border-b border-vanilla/10">
              <div className="flex items-center gap-2">
                <TerminalIcon size={16} className="text-orange" />
                <span className="font-pixel text-[10px] text-vanilla/60 uppercase tracking-widest">Message_Terminal v1.0</span>
              </div>
              <div className="flex gap-1.5">
                <div className="w-2.5 h-2.5 rounded-full bg-vanilla/10" />
                <div className="w-2.5 h-2.5 rounded-full bg-vanilla/10" />
                <div className="w-2.5 h-2.5 rounded-full bg-orange/40" />
              </div>
            </div>

            {/* Form Content */}
            <form onSubmit={handleSubmit} className="p-8 md:p-10 space-y-6">
              <AnimatePresence mode="wait">
                {isSubmitted ? (
                  <motion.div
                    key="success"
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -10 }}
                    className="h-[300px] flex flex-col items-center justify-center text-center"
                  >
                    <div className="w-16 h-16 rounded-full bg-orange/10 flex items-center justify-center mb-6">
                      <Send className="text-orange" size={24} />
                    </div>
                    <h3 className="font-heading text-[24px] font-bold text-vanilla mb-2">Transmission Sent</h3>
                    <p className="font-body text-vanilla/50">Your message has been encrypted and delivered.</p>
                  </motion.div>
                ) : (
                  <motion.div
                    key="form"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="space-y-6"
                  >
                    <div>
                      <label className="font-pixel text-[9px] text-orange uppercase block mb-2 tracking-widest">User_Identity</label>
                      <input 
                        type="text" 
                        placeholder="NAME_REQUIRED"
                        required
                        className="w-full bg-vanilla/[0.03] border border-vanilla/10 rounded-xl px-5 py-4 font-body text-vanilla focus:outline-none focus:border-orange/50 transition-colors placeholder:text-vanilla/10"
                        onChange={(e) => setFormState({...formState, name: e.target.value})}
                      />
                    </div>
                    <div>
                      <label className="font-pixel text-[9px] text-orange uppercase block mb-2 tracking-widest">Contact_Endpoint</label>
                      <input 
                        type="email" 
                        placeholder="EMAIL_REQUIRED"
                        required
                        className="w-full bg-vanilla/[0.03] border border-vanilla/10 rounded-xl px-5 py-4 font-body text-vanilla focus:outline-none focus:border-orange/50 transition-colors placeholder:text-vanilla/10"
                        onChange={(e) => setFormState({...formState, email: e.target.value})}
                      />
                    </div>
                    <div>
                      <label className="font-pixel text-[9px] text-orange uppercase block mb-2 tracking-widest">Packet_Payload</label>
                      <textarea 
                        placeholder="INITIATE_TRANSMISSION..."
                        required
                        rows={4}
                        className="w-full bg-vanilla/[0.03] border border-vanilla/10 rounded-xl px-5 py-4 font-body text-vanilla focus:outline-none focus:border-orange/50 transition-colors placeholder:text-vanilla/10 resize-none"
                        onChange={(e) => setFormState({...formState, message: e.target.value})}
                      />
                    </div>
                    <Magnet distance={15}>
                      <motion.button
                        whileHover={{ scale: 1.02 }}
                        whileTap={{ scale: 0.98 }}
                        type="submit"
                        className="w-full bg-orange text-white py-5 rounded-2xl font-heading font-bold text-[16px] flex items-center justify-center gap-2 group transition-shadow hover:shadow-[0_0_20px_rgba(254,81,2,0.3)] mt-4"
                      >
                        Transmit Message
                        <Send size={18} className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                      </motion.button>
                    </Magnet>
                  </motion.div>
                )}
              </AnimatePresence>
            </form>
          </motion.div>
        </div>
      </div>

      {/* Footer */}
      <motion.div
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, amount: 0.2 }}
        variants={itemVariants}
        className="max-w-[1400px] mx-auto mt-32 pt-8 border-t border-vanilla/5 flex flex-col sm:flex-row items-center justify-between gap-4"
      >
        <p className="font-pixel text-orange text-[9px] tracking-wider">ATHARAV NARANG</p>
        <p className="font-body text-[13px] text-vanilla/30">
          © {new Date().getFullYear()} All rights reserved.
        </p>
      </motion.div>
    </section>
  );
}
